import requests, json, datetime

TEAM_PROFILES = [
    {"name": "Alice Chen", "learn_username": "alicechen-mslearn"},
    {"name": "Bob Kumar", "learn_username": "bkumar-azure"},
    {"name": "Carol Wang", "learn_username": "cwang-devops"},
]

REQUIRED_PATHS = [
    "learn.azure.azure-fundamentals",
    "learn.azure.administrator-associate",
]

def fetch_profile(username: str) -> dict:
    try:
        resp = requests.get(
            f"https://learn.microsoft.com/api/profiles/{username}",
            timeout=15,
        )
        if not resp.ok:
            return {}
        return resp.json()
    except Exception:
        return {}

def paths_completed(profile_data: dict, required_uids: list[str]) -> list[str]:
    completed = {p for p in profile_data.get("completedLearningPaths", [])}
    return [uid for uid in required_uids if uid in completed]

def generate_team_report(team: list[dict], required_path_uids: list[str]) -> dict:
    report = {
        "generated_at": datetime.datetime.utcnow().isoformat(),
        "required_paths": required_path_uids,
        "members": [],
    }

    for member in team:
        profile = fetch_profile(member["learn_username"])
        completed = paths_completed(profile, required_path_uids)
        certs = [c.get("examCode") for c in profile.get("certifications", [])]

        report["members"].append({
            "name": member["name"],
            "username": member["learn_username"],
            "xp": profile.get("xp", 0),
            "level": profile.get("level", 1),
            "paths_completed": len(completed),
            "paths_remaining": len(required_path_uids) - len(completed),
            "certifications": certs,
            "on_track": len(completed) == len(required_path_uids),
        })

    report["summary"] = {
        "total_members": len(team),
        "on_track": sum(1 for m in report["members"] if m["on_track"]),
        "avg_xp": int(sum(m["xp"] for m in report["members"]) / len(team)) if team else 0,
    }
    return report

report = generate_team_report(TEAM_PROFILES, REQUIRED_PATHS)
print(json.dumps(report, indent=2))
